module multi_pipe_8bit(
    input clk,
    input rst_n,
    input mul_en_in,
    input [7:0] mul_a,
    input [7:0] mul_b,
    output mul_en_out,
    output [15:0] mul_out,
    input mul_en_in,
    output reg mul_en_out_reg,
    output mul_en_out,
    input mul_a,
    output reg mul_a_reg,
    input mul_b,
    output reg mul_b_reg,
    input sum,
    output sum,
    input mul_out_reg,
    output reg mul_out_reg,
    input mul_a_reg,
    input mul_b_reg,
    output temp
);

    reg [15:0] mul_out_reg;
    reg [7:0] mul_a_reg, mul_b_reg;
    reg [3:0] stage;
    reg mul_en_out_reg;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_out_reg <= 16'b0;
            mul_a_reg <= 8'b0;
            mul_b_reg <= 8'b0;
            stage <= 4'b0;
            mul_en_out_reg <= 1'b0;
        end else begin
            if (mul_en_in) begin
                mul_a_reg <= mul_a;
                mul_b_reg <= mul_b;
            end
            case (stage)
                4'b0000: mul_out_reg[7:0] <= mul_a_reg & {8{mul_b_reg[0]}};
                4'b0001: mul_out_reg[15:8] <= mul_a_reg & {8{mul_b_reg[1]}} + mul_out_reg[7:0];
                4'b0010: mul_out_reg[15:8] <= mul_a_reg & {8{mul_b_reg[2]}} + mul_out_reg[15:8];
                4'b0011: mul_out_reg[15:8] <= mul_a_reg & {8{mul_b_reg[3]}} + mul_out_reg[15:8];
                4'b0100: mul_out_reg[15:8] <= mul_a_reg & {8{mul_b_reg[4]}} + mul_out_reg[15:8];
                4'b0101: mul_out_reg[15:8] <= mul_a_reg & {8{mul_b_reg[5]}} + mul_out_reg[15:8];
                4'b0110: mul_out_reg[15:8] <= mul_a_reg & {8{mul_b_reg[6]}} + mul_out_reg[15:8];
                4'b0111: mul_out_reg[15:8] <= mul_a_reg & {8{mul_b_reg[7]}} + mul_out_reg[15:8];
                4'b1000: mul_out_reg[15:0] <= mul_out_reg[15:0];
                default: mul_out_reg[15:0] <= mul_out_reg[15:0];
            endcase
            if (stage < 4'b1000) begin
                stage <= stage + 1;
            end
            mul_en_out_reg <= mul_en_in;
        end
    end

    assign mul_en_out = mul_en_out_reg;
    assign mul_out = mul_out_reg;

endmodule
